import{_ as t,c,k as i,a as s,b as v,w as l,e,o as p,d as n}from"./CJ7kOIzE.js";import{u as o}from"./BVx0zj5Y.js";const f={class:"container page-section page-top-padding"},r={class:"flow-cta glass-card text-center"},w={__name:"flow",setup(g){return o({title:"代行の流れ - asuka",meta:[{name:"description",content:"asukaの中国輸入代行業務フロー。通常プランと、見積・清算プロセスをスキップして即時手配・即時発送を行うデポジットチャージ高速プランの流れを比較紹介。"}]}),(m,a)=>{const d=e;return p(),c("div",f,[a[3]||(a[3]=i('<h1 class="section-title" data-v-2651c024>代行の流れ</h1><p class="section-subtitle" data-v-2651c024> asukaのタオバオ・アリババ輸入代行サービスには、「通常プラン」と、手続きを大幅にスキップして買い付け・発送を急ぐ「デポジットチャージ高速プラン」の2つの流れがあります。 </p><div class="glass-card intro-banner animate-fade-in-up" data-v-2651c024><div class="banner-badge" data-v-2651c024><i class="fa-solid fa-gauge-high" data-v-2651c024></i> スピード重視の方へ</div><p data-v-2651c024> 「デポジットチャージ高速プラン」では、事前にお預かりしたデポジット（預け金）からお支払い・清算を自動処理するため、<strong data-v-2651c024>「見積書の確認」や「入金確認の待ち時間」が一切ありません。</strong><br data-v-2651c024> 通常のフローに比べて最短で商品を手配・発送することができます。 </p></div><div class="timeline-container" data-v-2651c024><div class="timeline-step" data-v-2651c024><div class="step-meta" data-v-2651c024><div class="step-num" data-v-2651c024>STEP 1</div><div class="step-image step-image--signup" data-v-2651c024></div></div><div class="step-flows" data-v-2651c024><div class="flow-panel normal-flow" data-v-2651c024><span class="flow-tag" data-v-2651c024>通常プラン</span><h4 data-v-2651c024>会員登録</h4><p data-v-2651c024>お申し込みフォームより会員登録を行ってください。「無料会員」「ゴールド会員」「無在庫会員」からご希望の種別をご選択いただけます。登録の際は必ず<strong data-v-2651c024>「チャットワークID」</strong>をご入力ください。</p></div><div class="flow-panel fast-flow" data-v-2651c024><span class="flow-tag fast-tag" data-v-2651c024>デポジットチャージ高速プラン</span><h4 data-v-2651c024>会員登録 &amp; デポジットチャージ</h4><p data-v-2651c024>通常会員登録に加え、高速手配を有効化するために、事前チャットワークにて合意した目安予算をデポジット（前払金）として弊社指定口座へチャージしていただきます。</p></div></div></div><div class="timeline-arrow" data-v-2651c024><i class="fa-solid fa-arrow-down" data-v-2651c024></i></div><div class="timeline-step" data-v-2651c024><div class="step-meta" data-v-2651c024><div class="step-num" data-v-2651c024>STEP 2</div><div class="step-image step-image--write" data-v-2651c024></div></div><div class="step-flows" data-v-2651c024><div class="flow-panel normal-flow" data-v-2651c024><span class="flow-tag" data-v-2651c024>通常プラン</span><h4 data-v-2651c024>オーダーシート作成</h4><p data-v-2651c024>弊社管理システムのマイページより、ご希望の商品情報を入力しオーダーシートを作成・ご提出ください。</p></div><div class="flow-panel fast-flow" data-v-2651c024><span class="flow-tag fast-tag" data-v-2651c024>デポジットチャージ高速プラン</span><h4 data-v-2651c024>オーダーシート作成</h4><p data-v-2651c024>通常プランと同様にマイページよりオーダーシートを作成・ご提出ください。提出と同時に手配プロセスが始まります。</p></div></div></div><div class="timeline-arrow" data-v-2651c024><i class="fa-solid fa-arrow-down" data-v-2651c024></i></div><div class="timeline-step" data-v-2651c024><div class="step-meta" data-v-2651c024><div class="step-num" data-v-2651c024>STEP 3</div><div class="step-image step-image--calculate" data-v-2651c024></div></div><div class="step-flows" data-v-2651c024><div class="flow-panel normal-flow" data-v-2651c024><span class="flow-tag" data-v-2651c024>通常プラン</span><h4 data-v-2651c024>お見積り ＆ 前金のお支払い</h4><p data-v-2651c024>ご注文確定後、商品代金に基づいたお見積書を発行します。チャットワークで通知が届きますので、前金をお支払いください。</p></div><div class="flow-panel fast-flow skipped-panel" data-v-2651c024><span class="flow-tag fast-tag" data-v-2651c024>デポジットチャージ高速プラン</span><div class="skip-badge" data-v-2651c024>SKIP <i class="fa-solid fa-circle-check" data-v-2651c024></i></div><h4 data-v-2651c024>お見積り確認のスキップ</h4><p data-v-2651c024>見積もり発行と入金確認の手続きをすべてスキップします。余分な連絡の往復がなく、時間ロスがゼロになります。</p></div></div></div><div class="timeline-arrow" data-v-2651c024><i class="fa-solid fa-arrow-down" data-v-2651c024></i></div><div class="timeline-step" data-v-2651c024><div class="step-meta" data-v-2651c024><div class="step-num" data-v-2651c024>STEP 4</div><div class="step-image step-image--buying" data-v-2651c024></div></div><div class="step-flows" data-v-2651c024><div class="flow-panel normal-flow" data-v-2651c024><span class="flow-tag" data-v-2651c024>通常プラン</span><h4 data-v-2651c024>商品買い付け開始</h4><p data-v-2651c024>お客様からの前金ご入金を弊社にて確認でき次第、現地の店舗または工場へ買い付けの手配をスタートします。</p></div><div class="flow-panel fast-flow highlight-panel" data-v-2651c024><span class="flow-tag fast-tag" data-v-2651c024>デポジットチャージ高速プラン</span><div class="speed-badge" data-v-2651c024>IMMEDIATE <i class="fa-solid fa-bolt" data-v-2651c024></i></div><h4 data-v-2651c024>ご注文確定後、即時買い付け</h4><p data-v-2651c024>オーダーシートの送信内容が確定した時点で、デポジットから充当する形で<strong data-v-2651c024>ただちに買い付けを行います。</strong>入金確認待ちがありません。</p></div></div></div><div class="timeline-arrow" data-v-2651c024><i class="fa-solid fa-arrow-down" data-v-2651c024></i></div><div class="timeline-step" data-v-2651c024><div class="step-meta" data-v-2651c024><div class="step-num" data-v-2651c024>STEP 5</div><div class="step-image step-image--liquidation" data-v-2651c024></div></div><div class="step-flows" data-v-2651c024><div class="flow-panel normal-flow" data-v-2651c024><span class="flow-tag" data-v-2651c024>通常プラン</span><h4 data-v-2651c024>検品・梱包・清算書の受領</h4><p data-v-2651c024>商品が中国倉庫に到着後、検品と二重梱包を行い、送料を含めた最終的な清算書（請求書）を発行します。差額のお支払いをお願いします。</p></div><div class="flow-panel fast-flow skipped-panel" data-v-2651c024><span class="flow-tag fast-tag" data-v-2651c024>デポジットチャージ高速プラン</span><div class="skip-badge" data-v-2651c024>SKIP <i class="fa-solid fa-circle-check" data-v-2651c024></i></div><h4 data-v-2651c024>発送前清算のスキップ</h4><p data-v-2651c024>発送前の追加清算手続きをスキップ。到着後すぐに発送作業に移行するため、出荷のタイミングを逃しません。</p></div></div></div><div class="timeline-arrow" data-v-2651c024><i class="fa-solid fa-arrow-down" data-v-2651c024></i></div><div class="timeline-step" data-v-2651c024><div class="step-meta" data-v-2651c024><div class="step-num" data-v-2651c024>STEP 6</div><div class="step-image step-image--sending" data-v-2651c024></div></div><div class="step-flows" data-v-2651c024><div class="flow-panel normal-flow" data-v-2651c024><span class="flow-tag" data-v-2651c024>通常プラン</span><h4 data-v-2651c024>国際発送</h4><p data-v-2651c024>送料および最終清算金額のご入金が確認でき次第、商品を日本（またはご指定の納品先）へ発送いたします。※関税等が発生した場合は商品到着時にお支払いください。</p></div><div class="flow-panel fast-flow highlight-panel" data-v-2651c024><span class="flow-tag fast-tag" data-v-2651c024>デポジットチャージ高速プラン</span><div class="speed-badge" data-v-2651c024>IMMEDIATE <i class="fa-solid fa-plane-departure" data-v-2651c024></i></div><h4 data-v-2651c024>検品完了後、即時発送</h4><p data-v-2651c024>検品完了後、即座に出荷手続きを行い発送します。発送後にデポジット残高より自動清算され、マイページにて清算内訳書が発行されます。</p></div></div></div></div>',4)),s("div",r,[a[1]||(a[1]=s("h3",null,"どちらのプランが最適か迷われていますか？",-1)),a[2]||(a[2]=s("p",null,"お客様の取扱品目や仕入れ頻度から、最適なプラン設定をご提案させていただきます。お気軽にご相談ください。",-1)),v(d,{to:"/contact",class:"btn-primary"},{default:l(()=>[...a[0]||(a[0]=[s("i",{class:"fa-solid fa-envelope"},null,-1),n(" プランの相談・問い合わせをする ",-1)])]),_:1})])])}}},_=t(w,[["__scopeId","data-v-2651c024"]]);export{_ as default};
